script.body:
param([string]$Path = '.', [string]$Filter = '*')

$resolvedPath = $Path

# If path is empty or just whitespace, use current directory
if (-not $Path -or $Path -match '^\s*$') {
    $resolvedPath = '.'
}
# Check if it looks like an actual path (drive letter, UNC, or relative with slashes)
elseif ($Path -match '^[a-zA-Z]:' -or $Path -match '^\\' -or $Path -match '^\.' -or $Path -match '[/\\]') {
    $resolvedPath = $Path
}
# Otherwise, check for known library names
else {
    $pathLower = $Path.ToLower().Trim()
    switch -Wildcard ($pathLower) {
        '*download*' { $resolvedPath = "$env:USERPROFILE\Downloads" }
        '*document*' { $resolvedPath = "$env:USERPROFILE\Documents" }
        '*picture*'  { $resolvedPath = "$env:USERPROFILE\Pictures" }
        '*photo*'    { $resolvedPath = "$env:USERPROFILE\Pictures" }
        '*music*'    { $resolvedPath = "$env:USERPROFILE\Music" }
        '*video*'    { $resolvedPath = "$env:USERPROFILE\Videos" }
        '*movie*'    { $resolvedPath = "$env:USERPROFILE\Videos" }
        '*desktop*'  { $resolvedPath = "$env:USERPROFILE\Desktop" }
        '*temp*'     { $resolvedPath = $env:TEMP }
        '*home*'     { $resolvedPath = $env:USERPROFILE }
        '*user*'     { $resolvedPath = $env:USERPROFILE }
        default      { $resolvedPath = $Path }
    }
}

if (-not (Test-Path $resolvedPath)) {
    Write-Output "Path not found: $resolvedPath"
    return
}

Write-Output "Listing: $resolvedPath"
Write-Output ('-' * 80)
Get-ChildItem -Path $resolvedPath -Filter $Filter | ForEach-Object { "{0,-50} {1,15:N0} bytes  {2}" -f $_.Name, $_.Length, $_.LastWriteTime }
